<template><div class="h-[calc(100vh-3.5rem)] overflow-y-auto p-4 space-y-4"><div class="flex gap-3 items-center"><div><h1 class="text-base text-gray-100 font-semibold">Calendário de Mercado</h1><p class="text-[10px] text-gray-600">macro · resultados · derivativos · COT</p></div><div class="flex-1"/><form @submit.prevent="load" class="flex gap-2"><input v-model="symbols" placeholder="AAPL,MSFT,PETR4.SA" class="form-input !py-1.5 text-xs w-48 uppercase"/><button class="btn-secondary !py-1.5 text-xs">Atualizar</button></form></div><div v-if="error" class="card p-3 text-red-400 text-xs">{{error}}</div><div class="card overflow-hidden" v-if="d"><div v-for="e in d.events" :key="e.date+e.title" class="grid grid-cols-[90px_80px_1fr_90px] gap-3 px-4 py-2 border-b border-surface-600 text-xs"><div class="font-mono text-gray-300">{{date(e.date)}}</div><div class="text-gray-600">{{e.time}}</div><div><span class="text-gray-200">{{e.title}}</span><small class="text-gray-600 ml-2">{{e.source}}</small></div><div class="text-right uppercase text-[9px]" :class="e.impact==='high'?'text-red-400':'text-amber-400'">{{e.category}} · {{e.impact}}</div></div></div><p class="text-[10px] text-gray-600">{{d?.note}}</p></div></template>
<script setup>import{ref,onMounted}from'vue';import{getMarketCalendar}from'@/api/client.js';const symbols=ref('AAPL,MSFT,BTC-USD'),d=ref(null),error=ref(null);const date=v=>new Date(v+'T12:00:00').toLocaleDateString('pt-BR');async function load(){try{d.value=(await getMarketCalendar(symbols.value)).data;error.value=null}catch(e){error.value=e.response?.data?.error||e.message}}onMounted(load)</script>
